# Security: Validates user credentials and issues an access token. Protects against unauthorized access by verifying password hashes and rejecting invalid credentials.
def authenticate_user(username: str, password: str):
    user = get_user_by_username(username)
    if not user or not verify_password(password, user.password_hash):
