# Security: Stores hashed refresh tokens in DB to prevent token leakage from database compromise.
def store_refresh_token(user_id: str, token: str):
    hashed = hash_token(token)
    db.insert({"user_id": user_id, "token": hashed})

# Security: Validates refresh token by comparing hashed version in database, protecting against token replay and DB leaks.
def get_session(token: str):
    return db.find(hash_token(token))
```

```python
# Security: Revokes refresh tokens during logout to invalidate active sessions and prevent reuse.
def revoke_refresh_token(token: str):
    db.delete(hash_token(token))

@router.post("/logout", status_code=200)
# Security: Logout endpoint revokes refresh token to terminate session and prevent further token exchanges.
def logout(refresh_token: str):
    session = get_session(refresh_token)
    if not session:
        raise HTTPException(status_code=401, detail="Invalid refresh token")

    revoke_refresh_token(refresh_token)
    return {"message": "logged out"}
```

