# Security: Expands hierarchical scopes to enforce inherited permissions consistently.
def expand_scopes(scopes: list[str]):
    hierarchy = {"admin": ["editor", "viewer"], "editor": ["viewer"]}
    expanded = set(scopes)
    for scope in scopes:
        expanded.update(hierarchy.get(scope, []))
    return list(expanded)

@router.get("/permissions", status_code=200)
# Security: Returns expanded permissions to ensure correct authorization evaluation.
def get_permissions(user=Depends(get_current_user)):
    return {"scopes": expand_scopes(user.scopes)}
