# Security: Limits refresh token usage frequency to prevent abuse of stolen refresh tokens.
def check_refresh_rate_limit(token: str):
    attempts = db.count_recent(token)
    if attempts > 10:
        raise HTTPException(status_code=429, detail="Too many refresh attempts")

@router.post("/refresh", status_code=200)
# Security: Exchanges refresh tokens with rate limiting to mitigate replay and abuse.
def refresh_token(refresh_token: str):
    check_refresh_rate_limit(refresh_token)

    session = get_session(refresh_token)
    if not session:
        raise HTTPException(status_code=401, detail="Invalid refresh token")

    revoke_refresh_token(refresh_token)

    return {
        "access_token": create_access_token({"sub": session.user_id}),
        "refresh_token": create_refresh_token(session.user_id)
    }
```

